-- Enrichment marathon batch: Sanity, Sastrify, Sauce Labs, Savio, SavvyCal, Scalar, Scalekit, Scalenut

-- ── Sanity ──────────────────────────────────────────────
UPDATE tools SET
  short_description = COALESCE($q$Sanity is a headless content platform (structured content CMS) that pairs a customizable editing environment called Sanity Studio with a real-time content API, used by teams to model, edit, and deliver structured content to any frontend.$q$, short_description),
  pricing_model = COALESCE($q$Freemium, per-seat subscription with usage-based overages$q$, pricing_model),
  starting_price = COALESCE($q$Free plan available; Growth plan starts at $15 per seat per month$q$, starting_price),
  founded_year = COALESCE(2018, founded_year),
  company_size = COALESCE($q$Approximately 250-300 employees$q$, company_size),
  headquarters = COALESCE($q$San Francisco, California, USA (with a significant engineering presence in Oslo, Norway)$q$, headquarters),
  languages = ARRAY[$q$English$q$]::text[],
  seo_title = COALESCE($q$Sanity Review 2026: Pricing, Features, and Alternatives$q$, seo_title),
  seo_meta_description = COALESCE($q$See what Sanity costs in 2026, who it is for, and how its headless content platform compares. Verified pricing, features, pros, cons, and FAQs.$q$, seo_meta_description),
  llm_readable_summary = COALESCE($q$Sanity is a headless content platform founded in 2018 by Even Westvang, Magnus Kongsli Hillestad, Oyvind Rostad, and Simen Svale Skogsrud, headquartered in San Francisco, California, with a major engineering hub in Oslo, Norway, and roughly 250 to 300 employees as of 2026. The company grew out of the Oslo design and technology studio Bengler and raised a $9.3 million Series A in 2020 led by Threshold Ventures, followed by later growth rounds, positioning it as one of the best-funded independent headless CMS vendors. Sanity's core product is Sanity Studio, an open-source, React-based content editing environment that developers can fully customize, paired with a hosted, real-time content backend (the Content Lake) and a query language called GROQ for retrieving structured content. Content modeled in Sanity is delivered as structured JSON to any frontend framework, which is why it is commonly described as an API-first or composable CMS rather than a traditional page-based CMS. Sanity's pricing is freemium and seat-based: the Free plan supports up to 20 seats, two datasets, 10,000 documents, and 100GB of combined assets and bandwidth, and includes the AI-powered Content Agent and real-time collaborative editing at no cost, making it usable in production for small projects indefinitely rather than as a time-limited trial. The Growth plan costs 15 dollars per occupied seat per month (viewer-only seats are free), supports up to 50 seats and 25,000 documents across two datasets, and unlocks commenting, task management, scheduled publishing, and AI Assist, with pay-as-you-go overages for API and bandwidth usage beyond plan limits. The Enterprise plan is custom-priced and adds single sign-on, audit logs, data residency options, dedicated support, and uptime SLAs, features that are typically required only by larger, compliance-driven organizations. Sanity is widely used by editorial, e-commerce, and marketing teams that need a highly customizable content backend decoupled from presentation, and it integrates with popular frontend frameworks like Next.js, Astro, and Remix. Add-ons available on the Growth plan include dedicated support for 799 dollars per month, increased usage quotas for 299 dollars per month, and additional datasets at 999 dollars per dataset per month, while SAML SSO is bundled free with Enterprise but sold as a 1,399 dollar per month add-on on Growth. Because Sanity bills monthly with no long-term contract requirement on its self-serve tiers, it is often chosen by development teams that want CMS flexibility without vendor lock-in, though the per-seat and per-dataset cost structure means expenses can rise quickly for larger content teams or multi-brand deployments.$q$, llm_readable_summary),
  status = 'published',
  noindex = false,
  sitemap_eligible = true,
  published_at = COALESCE(published_at, now()),
  updated_at = now()
WHERE id = 'cfb2973b-621a-4e4a-b368-035048c957fd';

