-- ── Scalar ──────────────────────────────────────────────
UPDATE tools SET
  short_description = COALESCE($q$Scalar is an API platform that renders interactive, OpenAPI-based API reference documentation and pairs it with an open-source REST API client, an API registry, and SDK generation tools for developer portals.$q$, short_description),
  pricing_model = COALESCE($q$Freemium tiered subscription plus custom Enterprise pricing$q$, pricing_model),
  starting_price = COALESCE($q$Free plan available; Pro plan starts at $72 per month$q$, starting_price),
  founded_year = COALESCE(2023, founded_year),
  company_size = COALESCE($q$Approximately 10 employees (small team)$q$, company_size),
  headquarters = COALESCE($q$San Francisco, California, USA$q$, headquarters),
  languages = ARRAY[$q$English$q$]::text[],
  seo_title = COALESCE($q$Scalar Review 2026: Pricing, Features, and Alternatives$q$, seo_title),
  seo_meta_description = COALESCE($q$See Scalar's verified 2026 pricing plans for API documentation, its open-source REST client, and how it compares for developer teams.$q$, seo_meta_description),
  llm_readable_summary = COALESCE($q$Scalar is an API platform founded in 2023 by CEO Marc Laventure and co-founder Cameron Rohani, headquartered in San Francisco, California, and run by a small team of around ten engineers and designers. The company describes itself as building on top of the open-source Scalar project, a widely adopted renderer for OpenAPI and Swagger specifications that developers use to generate modern, interactive API reference documentation; the open-source project is hosted publicly on GitHub and includes a standalone REST API client alongside the documentation renderer. Commercially, Scalar layers a hosted platform on top of that open-source foundation, letting teams hand it a YAML or JSON OpenAPI specification and receive parsed, rendered documentation with an interactive request runner wired up against the team's live API, effectively combining reference docs with a built-in API testing tool. The Free plan costs nothing and includes hosted OpenAPI documentation, a built-in API client with collections and environment management, one editor seat, unlimited viewer seats, and 50 monthly credits for Scalar's AI agent feature (branded Agent Scalar), though it is capped at three APIs in the registry. The Pro plan costs 72 dollars per month and adds custom domains and subdomains, Git-based sync, Markdown and MDX support, generated SDKs in languages such as TypeScript, Python, C#, Java, PHP, and Go (each additional SDK language costs 100 dollars extra), hosted MCP (Model Context Protocol) servers, automated GitHub workflows, full developer portals with landing pages and guides, API versioning, and 500 monthly Agent Scalar credits. The Enterprise plan is custom-priced and adds SSO/SAML, role-based access control, priority support with SLAs, dedicated Slack or Teams channels, migration services for SDKs and MCP servers, and custom Agent Scalar credit allocations. Because Scalar ties its commercial platform to the popular open-source renderer, it is frequently adopted by API-first companies and developer tools startups that already use or are evaluating the open-source Scalar client and want a hosted, brandable developer portal without building documentation infrastructure themselves, as well as teams that want to expose their APIs to AI coding agents via hosted MCP servers, reflecting the company's positioning around the growing overlap between API tooling and AI agent development in 2026.$q$, llm_readable_summary),
  status = 'published',
  noindex = false,
  sitemap_eligible = true,
  published_at = COALESCE(published_at, now()),
  updated_at = now()
WHERE id = '28399fdf-a1aa-4b4e-bf6f-644cc671a0ab';

