-- ── Scalekit ──────────────────────────────────────────────
UPDATE tools SET
  short_description = COALESCE($q$Scalekit is a B2B authentication infrastructure platform providing enterprise SSO, SCIM provisioning, and passwordless login for SaaS applications, along with an authentication and actions layer built for AI agent applications.$q$, short_description),
  pricing_model = COALESCE($q$Freemium, usage-based (tool calls/API usage) plus custom Enterprise pricing$q$, pricing_model),
  starting_price = COALESCE($q$Free plan available; Growth plan starts at $99 per month$q$, starting_price),
  founded_year = COALESCE(2023, founded_year),
  company_size = COALESCE($q$Small team; exact headcount not publicly disclosed (seed-stage startup)$q$, company_size),
  headquarters = COALESCE($q$United States (Delaware-registered), with an engineering office in Bengaluru, India$q$, headquarters),
  languages = ARRAY[$q$English$q$]::text[],
  seo_title = COALESCE($q$Scalekit Review 2026: Pricing, Features, and Alternatives$q$, seo_title),
  seo_meta_description = COALESCE($q$See Scalekit's verified 2026 pricing plans for SSO, SCIM, and AI agent authentication, plus company background and key features.$q$, seo_meta_description),
  llm_readable_summary = COALESCE($q$Scalekit is a B2B authentication infrastructure company founded in 2023 by Satya Padmanabham Devarakonda (CEO) and Ravi Krishna Kishore Madabhushi, registered in the United States (Delaware) with an engineering office operated through Scalekit Technologies India Private Limited in Bengaluru, India. The company raised a 5.5 million dollar seed round led by Together Fund and Z47, with angel investors including Adam Frankl, Oliver Jay, and Jagadeesh Kunda, and operates as a small, seed-stage team without a publicly disclosed exact headcount. Scalekit's core product helps B2B SaaS companies add enterprise-grade authentication features, including SAML and OIDC single sign-on, SCIM user provisioning, passkeys, magic links, social login, and one-time-passcode authentication, integrating with identity providers such as Okta, Microsoft Entra ID, OneLogin, and JumpCloud, and offering automatic certificate rotation so engineering teams don't have to build and maintain this infrastructure themselves. In 2026 the company has positioned itself heavily around a newer use case: authentication and authorization for AI agents, describing its platform as the 'auth stack for AI apps' that unifies human, AI agent, and API authentication in a single system, letting agentic applications authenticate incoming agents and securely connect to external tools on a user's behalf. Scalekit's AgentKit product is priced on a freemium, usage-based model tied to monthly 'tool calls': the Free plan includes 5,000 tool calls per month along with unlimited connected accounts, access to more than 500 pre-built connectors, the ability to bring your own API credentials, community and email support, and 30-day audit log retention, automatically prompting an upgrade to Growth once the free limit is exceeded. The Growth plan costs 99 dollars per month and includes 100,000 tool calls with overage billed at 0.50 dollars per additional 1,000 calls, adding custom connectors, an API proxy, white-label branding, private Slack support, unlimited development and staging environments, coding agent plugins, and an optional EU data residency add-on for an additional 99 dollars per month. The Enterprise plan is custom-priced with negotiated volume and rates, and adds VPC or on-premises deployment, a 99.99 percent uptime SLA, a forward-deployed engineer plus dedicated customer success manager, SIEM integrations, and audit log retention extendable up to one year. Scalekit is most relevant to B2B SaaS engineering teams that need to ship enterprise SSO and provisioning quickly to close enterprise deals, as well as newer AI-native companies building agentic products that need a way to authenticate and authorize AI agents acting on behalf of users across external tools.$q$, llm_readable_summary),
  status = 'published',
  noindex = false,
  sitemap_eligible = true,
  published_at = COALESCE(published_at, now()),
  updated_at = now()
WHERE id = 'f089f3d0-931d-41ab-b83c-765e387a247e';

UPDATE tools SET logo = 'https://www.google.com/s2/favicons?domain=' || regexp_replace(regexp_replace(website, '^https?://', ''), '/.*$', '') || '&sz=256' WHERE id = 'f089f3d0-931d-41ab-b83c-765e387a247e' AND logo IS NULL AND website IS NOT NULL;

