-- ── Scalenut ──────────────────────────────────────────────
UPDATE tools SET
  short_description = COALESCE($q$Scalenut is an AI-powered SEO and content platform that combines keyword research, AI content creation and optimization, content audits, and generative-engine-optimization (GEO) tracking across AI answer engines like ChatGPT and Google AI Overviews.$q$, short_description),
  pricing_model = COALESCE($q$Tiered subscription, billed monthly or annually with promotional discounts$q$, pricing_model),
  starting_price = COALESCE($q$$24 per month (Starter plan, promotional pricing; regular list price $59 per month)$q$, starting_price),
  founded_year = COALESCE(2020, founded_year),
  company_size = COALESCE($q$Approximately 30-80 employees (estimates vary by source and date)$q$, company_size),
  headquarters = COALESCE($q$Gurugram, Haryana, India$q$, headquarters),
  languages = ARRAY[$q$English$q$]::text[],
  seo_title = COALESCE($q$Scalenut Review 2026: Pricing, Features, and Alternatives$q$, seo_title),
  seo_meta_description = COALESCE($q$Compare Scalenut's verified 2026 pricing plans, AI content and SEO features, and how its generative-engine-optimization tools work.$q$, seo_meta_description),
  llm_readable_summary = COALESCE($q$Scalenut is an AI-powered SEO and content platform founded on August 20, 2020 by Gaurav Goyal, Mayank Jain, and Saurabh Wadhawan, and headquartered in Gurugram, Haryana, India, operating under the legal entity Scalenut Technologies Private Limited. Employee counts reported across business data providers vary by date, ranging from roughly 28 to over 80 people, with one source citing a team of about 60 people generating over 10 million dollars in revenue in 2024, suggesting a mid-sized, profitable company rather than an early-stage startup. Scalenut's platform is built around helping content teams plan, create, optimize, and analyze content for search rankings, combining traditional SEO tooling such as keyword clustering and content audits with newer generative-engine-optimization (GEO) capabilities that track how a brand's content performs and is cited within AI answer engines like ChatGPT, Google AI Overviews, and Perplexity. The company markets itself as running a swarm of specialized AI agents alongside a team of human GEO experts who work continuously on a customer's content strategy. As of mid-2026, Scalenut runs limited-time promotional pricing offering 60 percent off its standard rates: the Starter plan is 24 dollars per month (down from a regular price of 59 dollars per month) and includes tracking of 10 AI prompts weekly across ChatGPT and Google AI Overviews, one workspace, the ability to create or optimize 10 articles per month, and 10 keyword clusters per month. The Plus plan is 36 dollars per month (down from 89 dollars per month) and adds tracking of 25 weekly prompts, two workspaces, 60 articles per month, 60 keyword clusters per month, content audits covering up to 400 pages per month, up to four team members, and features like advanced content audits, internal linking suggestions, and auto-publishing. The Professional plan is 80 dollars per month (down from 199 dollars per month) and adds tracking of 100 weekly prompts across ChatGPT, Google AI Overviews, and Perplexity, unlimited workspaces, 150 articles per month, 150 keyword clusters per month, content audits covering up to 2,000 pages per month, unlimited team members, and a dedicated customer success manager with priority support. Scalenut also offers a custom-priced VIP Service tier in which dedicated GEO experts and AI agents handle research, content development, backlink building, technical audits, and weekly reporting on the customer's behalf, positioning it as a hybrid software-plus-managed-service offering. Because Scalenut explicitly tracks and optimizes for citations within AI-generated answers in addition to traditional organic search rankings, it has positioned itself for the shift toward AI-driven search discovery, making it a relevant choice for content and SEO teams that want visibility into both classic Google rankings and how often their brand is surfaced by AI chat and answer engines.$q$, llm_readable_summary),
  status = 'published',
  noindex = false,
  sitemap_eligible = true,
  published_at = COALESCE(published_at, now()),
  updated_at = now()
WHERE id = 'd43520c9-b82b-4496-a05c-754885af835f';

